#include <iostream>
using namespace std;
int n,m;
bool a[1000005];
int main() {
	cin>>n>>m;
	int k=0,l=0;
	for(int i=1;i<n;i++){
		while(k<m){
			l++;
			if(l>n){
				l=1;
			}
			if(a[l]==0){
				k++;
			}
		}
		a[l]=1;
		cout<<l<<" ";
		k=0;
	}
	for(int i=1;i<=n;i++){
		if(a[i]==0){
			cout<<i;
			return 0;
		}
	}
	return 0;
}
